	                    qry_match_len += tmin(edgelen, mustmatch);
	                    mustmatch = tmax(dist_to_edge_end, 0);
	                }
	                else {
	                    qry_match_len++;
	                    refpos = node_start + 1;
	                }
	            }

	            c = GETQCHAR(qrystart + qry_match_len);

	            while (refpos <= node_end && c != '\0') 
